import { Pipe, PipeTransform } from '@angular/core';

const kb = 1024;
const mb = 1024 * kb;
const gb = 1024 * mb;

@Pipe({
  name: 'fileSize',
  standalone: true,
})
export class FileSizePipe implements PipeTransform {

  public transform(size: number): string {
    if(!size){
      return `0K`;
    }
    if (size < kb) {
      return `${size}B`;
    }
    if (size >= kb && size < mb) {
      return `${(size / kb).toFixed(2)}K`;
    }
    if (size >= mb && size <= gb) {
      return `${(size / mb).toFixed(2)}M`;
    }
    if (size >= gb) {
      return `${(size / gb).toFixed(2)}G`;
    }
    return '';
  }

}

import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'formatNumber',
  standalone: true
})
export class FormatNumberPipe implements PipeTransform {
  transform(value: number, decimals: number = 1): string {
    if (value === null || value === undefined) return '0';

    if (value >= 1000000000) {
      const num = value / 1000000000;
      return this.formatWithDecimals(num, decimals) + 'B';
    }

    if (value >= 1000000) {
      const num = value / 1000000;
      return this.formatWithDecimals(num, decimals) + 'M';
    }

    if (value >= 1000) {
      const num = value / 1000;
      return this.formatWithDecimals(num, decimals) + 'K';
    }

    return value.toString();
  }

  private formatWithDecimals(num: number, decimals: number): string {
    const rounded = Math.round(num * Math.pow(10, decimals)) / Math.pow(10, decimals);
    return rounded % 1 === 0 ? rounded.toString() : rounded.toFixed(decimals);
  }
}

import { Pipe, PipeTransform } from "@angular/core";
import { NzI18nService } from "ng-zorro-antd/i18n";

@Pipe({
    name: 'translate',
    standalone: true,
    pure: false
})
export class TranslatePipe implements PipeTransform {
    private value: any;
    private path: string;
    private lastResult: string;

    constructor(private i18n: NzI18nService) {
        this.i18n.localeChange.subscribe(() => {
            if (this.path?.trim()) {
                this.lastResult = this.i18n.translate(this.path);
            }
        });
    }

    transform(value: any, ...args: any[]): string {
        this.path = args[0];
        this.value = value;

        // 如果提供了翻译路径，直接使用翻译路径进行翻译
        if (this.path?.trim()) {
            this.lastResult = this.i18n.translate(this.path);
            return this.lastResult;
        }

        // 如果没有提供翻译路径，但提供了值，尝试直接翻译该值
        if (value?.trim()) {
            this.lastResult = this.i18n.translate(value);
            return this.lastResult;
        }

        // 如果都没有，返回空字符串
        return '';
    }
}

